(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,41074,a=>{"use strict";a.s(["profileData",0,{ru:{metaTitle:"Mikhail Fedrunov — 1С-разработчик / бизнес-аналитик / специалист по автоматизации",nav:{profile:"Профиль",experience:"Опыт",cases:"Кейсы",skills:"Навыки",cv:"Резюме"},heroKicker:"КАРТОЧКА СПЕЦИАЛИСТА · БИЗНЕС-СИСТЕМЫ",heroTitle:"Автоматизирую бизнес-процессы, а не просто пишу код.",heroLead:"1С-разработчик и бизнес-аналитик с практическим опытом автоматизации торговли, производства, склада и бухгалтерии. Самостоятельно веду задачи от разговора с пользователями и разбора процесса до разработки, тестирования, внедрения и поддержки. Поддерживаю более 300 пользователей и девять информационных баз, включая три основные рабочие базы производственной и дистрибьюторской компаний. Сильнейшие направления: СКД и сложные запросы, расширения и внешние обработки, HTTP/True API, JSON/XML/FTP, фоновые задания, маркировка и DataMatrix, обмены между базами и печатные формы.",role:"1С-разработчик / бизнес-аналитик / специалист по автоматизации",location:"Симферополь, Крым",relocation:"Готов к переезду в Сербию сразу после оффера; требуется помощь с разрешением на работу и легализацией.",status:"Открыт к предложениям в Сербии",buttons:{pdf:"Открыть PDF",docx:"Скачать DOCX",contact:"Связаться"},formLabels:{status:"Статус",focus:"Специализация",scale:"Масштаб",location:"Локация"},formValues:{status:"Готов к релокации",focus:"1С · аналитика · интеграции",scale:"300+ пользователей · 9 баз",location:"Симферополь → Сербия"},metrics:[["300+","пользователей в поддержке"],["3 / 9","рабочих / всего баз"],["end to end","от требования до внедрения"],["несколько дней","ручной работы экономит ключевая проверка"]],profileLabel:"ЦЕННОСТЬ ДЛЯ КОМПАНИИ",profileTitle:"Разработка, анализ и надёжность в одном специалисте.",profileText:"Объединяю три компетенции: разработку 1С, анализ бизнес-процессов и контроль качества данных и интеграций.",competencies:[["Разработка 1С","1С:Предприятие 8.3; УТ, БП, ЗУП; расширения; внешние обработки и отчёты; документы; регистры сведений; формы; печатные макеты."],["Запросы и аналитика","СКД, сложные запросы, соединения, группировки, аналитические разрезы, сверка данных между источниками, отчёты для подразделений и руководства."],["Интеграции","HTTP и True API, получение токенов, БСП, FTP, JSON, XML, CSV, TXT, обмен данными с внешними приложениями и сервисами."],["Автоматизация и надёжность","Фоновые и регламентные задания, пакетная обработка, контроль дублей, журналирование ошибок, проверка API и межсистемных обменов."],["Бизнес-анализ","Интервью с пользователями, анализ процесса «как есть», проектирование целевого решения, согласование логики, внедрение и обучение пользователей."],["Сопровождение","Поддержка 300+ пользователей, оперативный разбор инцидентов, сопровождение трёх рабочих и шести тестовых/разрабатываемых баз."]],experienceLabel:"ОПЫТ",experienceTitle:"Понимаю бизнес изнутри и умею превращать требования в работающие инструменты.",experience:[{company:"ТД «Время», Симферополь",role:"Инженер-системный программист / 1С-разработчик",period:"Январь 2026 — настоящее время",intro:"Производственная и дистрибьюторская компании. Основной специалист по прикладным задачам 1С: разработка, интеграции, аналитика и поддержка пользователей.",bullets:["Поддерживаю более 300 пользователей, три основные рабочие базы и шесть тестовых и разрабатываемых баз.","Самостоятельно собираю требования у бухгалтерии, продаж, логистики, склада, производства и руководства; предлагаю техническую реализацию и довожу задачу до рабочего результата.","Разрабатываю расширения, внешние обработки и отчёты, документы, регистры сведений, формы, СКД-отчёты и печатные макеты.","Создаю интеграции через HTTP/True API, FTP, JSON и XML; использую БСП для серверных запросов, авторизации и получения токенов.","Настраиваю фоновые и регламентные задания для загрузки файлов, массовой проверки данных, обработки кодов и рассылки отчётов.","Дорабатываю обмены между информационными базами, планы обмена, XML-переносы и правила Конвертации данных 2.1.","Проверяю внедрения на тестовых базах, сопровождаю запуск и оперативно исправляю найденные пользователями ошибки.","Готовлю инструкции и объясняю сотрудникам логику новых инструментов и изменённых процессов."]},{company:"ОВК-Терм, Симферополь",role:"Оператор 1С → логист → менеджер по работе с актами → заместитель начальника склада",period:"Январь 2023 — ноябрь 2025",intro:"Прошёл путь от операционной работы в 1С до координации складских и логистических процессов. Этот опыт сформировал сильную прикладную базу для последующей автоматизации бизнеса.",bullets:["Работал с полным циклом движения товара: приёмка, размещение, перемещение, комплектация, отгрузка, доставка, возвраты и инвентаризации.","Анализировал расхождения между данными 1С, первичными документами и фактическими операциями склада и логистики.","Координировал работу склада, логистов, водителей, менеджеров и бухгалтерии; согласовывал требования нескольких подразделений.","Контролировал корректность актов, перемещений, отгрузок, складских остатков и сопроводительных документов.","Создавал отчёты и инструменты Excel со сложными формулами, сводными таблицами и VBA, сокращая ручную подготовку и сверку данных.","Формализовывал процессы и составлял инструкции для сотрудников."]}],casesLabel:"ПРОЕКТЫ В ПРОДАКШЕНЕ",casesTitle:"Кейсы с бизнес-задачей, реализацией и измеримым результатом.",casesIntro:"Наведение раскрывает суть проекта; клик открывает полный кейс.",cases:[{id:"CASE-001",title:"Сверка исходящих УПД с системой «Честный знак»",short:"Фоновая проверка документов и владельцев кодов через True API.",challenge:"Статус ЭДО в бухгалтерской базе не всегда давал достаточную уверенность. Сотрудники дополнительно проверяли документы и коды маркировки вручную, что занимало до нескольких рабочих дней.",solution:"Разработал обработку для БП 3.0 с выбором организации и периода. Она находит реализации и УПД, требующие проверки, обращается к True API по идентификатору документа, извлекает коды из УПД и проверяет текущего владельца каждого кода. Массовая проверка выполняется фоновыми заданиями с контролем статуса и понятным итоговым протоколом.",result:"Пользователь получает единую таблицу с реализациями, УПД, статусами, идентификаторами и количеством кодов, а также отдельную выгрузку TXT. Многодневная ручная сверка заменена одним запуском и анализом готового результата.",stack:"1С:Бухгалтерия 3.0 · True API · HTTP · SSL · БСП · фоновые задания · DataMatrix"},{id:"CASE-002",title:"Загрузка DataMatrix из мобильного приложения",short:"Автоматический приём JSON с FTP и сопоставление с объектами 1С.",challenge:"Торговые агенты при наличной продаже сканируют торговую точку и коды блоков и коробов. Бизнесу требовалось централизованно собирать эти данные и связывать их с учётом.",solution:"Настроил получение JSON-файлов с FTP, парсинг даты загрузки и продажи, агента, торговой точки и DataMatrix-кодов. Добавил сопоставление с пользователями, партнёрами, номенклатурой и маршрутами, собственный регистр сведений, контроль дублей и журналирование ошибок.",result:"Данные поступают в 1С автоматически и становятся пригодными для аналитики без ручной сборки файлов. Ошибки сопоставления не теряются, а фиксируются для последующей обработки.",stack:"1С:УТ · FTP · JSON · регламентные задания · регистры сведений · DataMatrix"},{id:"CASE-003",title:"Контроль сканирования по агентам и подразделениям",short:"Сверка сканов из приложения с фактическими продажами бухгалтерской базы.",challenge:"Руководству было необходимо видеть, какие агенты сканируют маркированную продукцию, где сканы отсутствуют и насколько они соответствуют реальным продажам.",solution:"Разработал отчёты с группировкой по подразделениям и агентам, переводом блоков и коробов в пачки, итогами и списками сотрудников без сканов. Данные приложения сопоставляются с продажами из бухгалтерской базы.",result:"Руководители получают понятную картину по каждому подразделению и агенту: кто не сканирует, кто сканирует не полностью и где есть расхождения с учётом.",stack:"1С · СКД · сложные запросы · регистры сведений · межбазовая сверка · Excel"},{id:"CASE-004",title:"Локальные веб-инструменты для кодов маркировки",short:"Набор HTML/JavaScript-утилит для массовой работы с TXT, CSV и XML.",challenge:"Большие массивы кодов регулярно приходилось объединять, сравнивать, очищать и конвертировать вручную, при этом нельзя было потерять или изменить ни один символ DataMatrix.",solution:"Создал автономные браузерные инструменты для извлечения кодов из XML, преобразования CSV↔TXT, поиска и удаления дублей, объединения файлов, удаления списанных кодов, разделения пачек и блоков, подсчёта итогов и обратной сверки.",result:"Операции выполняются локально без установки ПО и передачи файлов внешним сервисам. Пользователь видит статистику, ошибки и получает готовые файлы для скачивания.",stack:"HTML · CSS · JavaScript · File API · CSV/XML/TXT · DataMatrix"},{id:"CASE-005",title:"Печатные формы и массовое формирование PDF",short:"Многостраничные формы с динамическими реквизитами и подписантами.",challenge:"Типовые формы не учитывали внутренние правила по организациям, подписантам, датам и составу комплектов документов.",solution:"Разрабатывал и дорабатывал товарно-транспортные накладные, требования, уведомления и внутренние формы. Реализовывал динамический выбор подписантов, расчёт итогов, рабочие даты, многостраничный вывод и массовое сохранение отдельных PDF.",result:"Документы формируются по правилам компании и готовы к печати без ручной правки. Массовая выгрузка ускоряет подготовку комплектов.",stack:"1С · табличный документ · макеты · печатные формы · PDF"},{id:"CASE-006",title:"Сопровождение обменов между базами",short:"Планы обмена, КД 2.1, XML и выборочный перенос документов.",challenge:"Обмены между базами требовали доработки правил, контроля регистрации объектов и разбора ошибок переноса.",solution:"Дорабатывал планы обмена и правила КД 2.1, анализировал состав выгрузки, настраивал выборочный перенос документов и работал с XML-форматом обмена.",result:"Нужные документы и реквизиты передаются между контурами предсказуемо, а ошибки локализуются на уровне правила или объекта.",stack:"1С · КД 2.1 · планы обмена · XML · фоновые задания"}],caseLabels:{challenge:"Бизнес-задача",solution:"Что реализовано",result:"Результат",stack:"Технологии",open:"Открыть кейс",close:"Закрыть"},workflowLabel:"ПОДХОД К РАБОТЕ",workflowTitle:"От проблемы пользователя до устойчивого решения в рабочей базе.",workflow:[["01","Разобраться","Поговорить с пользователями, проверить документы и данные, понять настоящий источник проблемы."],["02","Спроектировать","Определить объекты 1С, интеграции, проверки, сценарии ошибок и понятный интерфейс."],["03","Разработать","Собрать решение, фоновые процессы, отчёты и инструменты контроля."],["04","Внедрить","Проверить на тестовой базе, запустить, объяснить пользователям и сопровождать результат."]],skillsLabel:"ТЕХНОЛОГИИ",skillsTitle:"Рабочий стек",skills:["1С:Предприятие 8.3","УТ / БП / ЗУП","СКД и язык запросов","Расширения и внешние обработки","HTTP / True API / БСП","FTP / JSON / XML / CSV / TXT","Фоновые и регламентные задания","КД 2.1 и планы обмена","DataMatrix / Честный знак","HTML / CSS / JavaScript","Excel / VBA","Git / Postman — базовый опыт"],toolsLabel:"РАБОЧИЕ ДЕМО",toolsTitle:"Локальные инструменты, которыми реально пользовались для обработки кодов.",demoOpen:"Открыть инструмент",demos:[["Извлечение кодов из XML","Получение DataMatrix из нескольких XML-файлов в готовый TXT.","demos/xml-to-txt.html"],["Поиск и удаление дублей","Проверка больших наборов кодов с итогами и отдельной выгрузкой.","demos/deduplicate.html"],["Очистка от списанных кодов","Сравнение нескольких исходников со списанными кодами и формирование очищенных файлов.","demos/remove-codes.html"],["TXT → CSV для Честного знака","Подготовка структурированного CSV для последующей загрузки.","demos/txt-to-csv.html"]],cvLabel:"ПОЛНОЕ РЕЗЮМЕ",cvTitle:"Один универсальный профиль для оценки кандидата.",cvText:"PDF готов к отправке и печати. DOCX доступен для внутренней работы рекрутера. Язык документа соответствует выбранному языку сайта.",cvOther:"Другие языки",contactLabel:"КОНТАКТ",contactTitle:"Готов обсудить задачи, формат работы и переезд в Сербию.",footer:"Портфолио бизнес-систем и автоматизации",commandText:"Открыть профиль кандидата",caseStatus:"В РАБОЧЕЙ БАЗЕ",pdfHint:"Готов к отправке и печати",docxHint:"Редактируемый документ",systemStatus:"СИСТЕМА ГОТОВА"},en:{metaTitle:"Mikhail Fedrunov — 1C Developer / Business Analyst / Automation Specialist",nav:{profile:"Profile",experience:"Experience",cases:"Cases",skills:"Skills",cv:"CV"},heroKicker:"SPECIALIST PROFILE · BUSINESS SYSTEMS",heroTitle:"I automate business processes, not just code features.",heroLead:"1C developer and business analyst with hands-on experience automating sales, manufacturing, warehouse and accounting processes. I own tasks end to end: user interviews, process analysis, solution design, development, testing, rollout and support. I support more than 300 users and nine information bases, including three production systems for manufacturing and distribution companies. My strongest areas are DCS and complex queries, extensions and external processors, HTTP/True API, JSON/XML/FTP, background jobs, product marking and DataMatrix, cross-database exchanges and print forms.",role:"1C Developer / Business Analyst / Automation Specialist",location:"Simferopol, Crimea",relocation:"Ready to relocate to Serbia immediately after an offer; requires employer support with work authorization and legalization.",status:"Open to opportunities in Serbia",buttons:{pdf:"Open PDF",docx:"Download DOCX",contact:"Contact"},formLabels:{status:"Status",focus:"Focus",scale:"Scale",location:"Location"},formValues:{status:"Ready to relocate",focus:"1C · analysis · integrations",scale:"300+ users · 9 databases",location:"Simferopol → Serbia"},metrics:[["300+","supported users"],["3 / 9","production / total databases"],["end to end","from requirement to production"],["several days","of manual work saved by the key verification tool"]],profileLabel:"VALUE FOR THE COMPANY",profileTitle:"Development, analysis and reliability in one specialist.",profileText:"Combines three disciplines in one accountable role: 1C development, business analysis, and data/integration quality control.",competencies:[["1C development","1C:Enterprise 8.3; Trade Management, Accounting, Payroll; extensions; external processors and reports; documents; information registers; forms and print layouts."],["Queries and analytics","Data Composition System, complex queries, joins, grouping, analytical dimensions, cross-source reconciliation and management reporting."],["Integrations","HTTP and True API, token-based authorization, Standard Subsystems Library, FTP, JSON, XML, CSV and TXT."],["Automation and reliability","Background and scheduled jobs, batch processing, duplicate control, error logging, API validation and inter-system exchange checks."],["Business analysis","User interviews, as-is process analysis, target solution design, logic alignment, rollout and user training."],["Application support","Support for 300+ users and three production plus six test/development information bases."]],experienceLabel:"EXPERIENCE",experienceTitle:"I understand operations from the inside and turn requirements into working tools.",experience:[{company:"TD Vremya, Simferopol",role:"Systems Programmer / 1C Developer",period:"January 2026 — Present",intro:"Manufacturing and distribution companies. Primary specialist for applied 1C work: development, integrations, analytics and user support.",bullets:["Support more than 300 users, three production information bases and six test or development bases.","Gather requirements from accounting, sales, logistics, warehouse, manufacturing and management; propose the technical design and deliver the working solution.","Develop extensions, external processors and reports, documents, information registers, forms, DCS reports and print layouts.","Build integrations through HTTP/True API, FTP, JSON and XML; use the Standard Subsystems Library for server requests, authorization and token handling.","Configure background and scheduled jobs for file ingestion, bulk validation, code processing and report delivery.","Maintain cross-database exchanges, exchange plans, XML transfers and Data Conversion 2.1 rules.","Test changes in test bases, support production rollout and fix issues reported by users.","Prepare user instructions and explain the business logic of new tools and changed processes."]},{company:"OVK-Term, Simferopol",role:"1C Operator → Logistician → Acts Manager → Deputy Warehouse Manager",period:"January 2023 — November 2025",intro:"Progressed from operational 1C work to coordination of warehouse and logistics processes. This experience formed a strong business foundation for later automation work.",bullets:["Worked with the full goods movement cycle: receiving, storage, transfer, picking, shipment, delivery, returns and inventory counts.","Analysed discrepancies between 1C data, primary documents and actual warehouse and logistics operations.","Coordinated warehouse staff, logisticians, drivers, managers and accounting, aligning requirements across departments.","Controlled acts, transfers, shipments, warehouse balances and accompanying documentation.","Built Excel tools using complex formulas, pivot tables and VBA to reduce manual preparation and reconciliation.","Formalized working procedures and prepared employee instructions."]}],casesLabel:"PRODUCTION CASES",casesTitle:"Cases with business context, implementation and measurable impact.",casesIntro:"Hover reveals the project structure; click opens the full case.",cases:[{id:"CASE-001",title:"Outgoing UTD reconciliation with Chestny ZNAK",short:"Background verification of documents and product-code ownership through True API.",challenge:"EDI status in the accounting system did not always provide enough certainty. Employees additionally checked documents and marking codes manually, which could take several working days.",solution:"Built an Accounting 3.0 processor with organization and period filters. It finds sales and UTD documents that require verification, calls True API by document identifier, extracts codes from the UTD and checks the current owner of each code. Bulk checks run as background jobs with status tracking and a clear result protocol.",result:"The user receives one table with sales documents, UTDs, statuses, identifiers and code counts, plus optional TXT export. A multi-day manual procedure is replaced by one run and review of the result.",stack:"1C Accounting 3.0 · True API · HTTP · SSL · Standard Subsystems Library · background jobs · DataMatrix"},{id:"CASE-002",title:"DataMatrix ingestion from a mobile application",short:"Automated JSON ingestion from FTP and matching to 1C master data.",challenge:"Sales agents scan a retail location and pack/case codes during cash sales. The business needed a centralized way to collect and connect this information to accounting data.",solution:"Implemented FTP retrieval of JSON files and parsing of upload date, sale date, agent, retail location and DataMatrix codes. Added matching to users, partners, products and routes, a custom information register, duplicate control and error logging.",result:"Data enters 1C automatically and becomes ready for analytics without manual file assembly. Matching errors are preserved and logged for follow-up.",stack:"1C Trade Management · FTP · JSON · scheduled jobs · information registers · DataMatrix"},{id:"CASE-003",title:"Agent and division scanning control",short:"Reconciliation of mobile scans against actual sales in the accounting system.",challenge:"Management needed to see which agents scan marked products, where scans are missing and whether scan volumes match actual sales.",solution:"Developed reports grouped by division and agent, with conversion of blocks and cases into packs, totals and explicit lists of employees without scans. Application data is reconciled with sales from the accounting base.",result:"Managers receive a clear view by division and agent: no scanning, incomplete scanning and discrepancies against accounting records.",stack:"1C · DCS · complex queries · information registers · cross-database reconciliation · Excel"},{id:"CASE-004",title:"Local browser utilities for marking codes",short:"A set of HTML/JavaScript tools for bulk TXT, CSV and XML processing.",challenge:"Large code sets repeatedly had to be merged, compared, cleaned and converted by hand while preserving every DataMatrix character exactly.",solution:"Created standalone browser tools for XML extraction, CSV↔TXT conversion, duplicate detection/removal, file merging, written-off code removal, pack/case separation, totals and reverse reconciliation.",result:"Bulk operations run locally without software installation or uploading files to external services. Users see statistics and errors and receive downloadable output files.",stack:"HTML · CSS · JavaScript · File API · CSV/XML/TXT · DataMatrix"},{id:"CASE-005",title:"Print forms and batch PDF generation",short:"Multi-page documents with dynamic details, dates and signatories.",challenge:"Standard print forms did not cover internal rules for legal entities, signatories, dates and document packages.",solution:"Developed and maintained transport invoices, requirements, notices and internal forms. Implemented dynamic signatories, totals, business-day dates, multi-page output and batch saving of separate PDFs.",result:"Documents are generated according to company rules and are ready to print without manual edits. Batch export accelerates preparation of document packages.",stack:"1C · spreadsheet document · print layouts · PDF"},{id:"CASE-006",title:"Cross-database exchange support",short:"Exchange plans, Data Conversion 2.1, XML and selective document transfer.",challenge:"Cross-database exchanges required changes to rules, object registration control and investigation of transfer errors.",solution:"Adjusted exchange plans and Data Conversion 2.1 rules, analysed export contents, configured selective document transfer and worked with XML exchange format.",result:"Required documents and attributes move between systems predictably, while failures can be isolated to a rule or object.",stack:"1C · Data Conversion 2.1 · exchange plans · XML · background jobs"}],caseLabels:{challenge:"Business challenge",solution:"Implementation",result:"Impact",stack:"Technology",open:"Open case",close:"Close"},workflowLabel:"WORKING APPROACH",workflowTitle:"From a user problem to a stable production solution.",workflow:[["01","Understand","Interview users, inspect documents and data, and identify the actual source of the problem."],["02","Design","Define 1C objects, integrations, validation, error scenarios and a usable interface."],["03","Build","Implement the solution, background processes, reports and control tools."],["04","Deliver","Test in a separate base, roll out, train users and support the result."]],skillsLabel:"TECHNOLOGY",skillsTitle:"Working stack",skills:["1C:Enterprise 8.3","Trade / Accounting / Payroll","DCS and 1C query language","Extensions and external processors","HTTP / True API / SSL","FTP / JSON / XML / CSV / TXT","Background and scheduled jobs","Data Conversion 2.1 and exchange plans","DataMatrix / Chestny ZNAK","HTML / CSS / JavaScript","Excel / VBA","Git / Postman — basic experience"],toolsLabel:"WORKING DEMOS",toolsTitle:"Local tools actually used for product-code processing.",demoOpen:"Open tool",demos:[["Extract codes from XML","Extract DataMatrix values from multiple XML files into a ready TXT file.","demos/xml-to-txt.html"],["Find and remove duplicates","Validate large code sets with totals and separate output.","demos/deduplicate.html"],["Remove written-off codes","Compare multiple source files against written-off codes and generate cleaned outputs.","demos/remove-codes.html"],["TXT to CSV for Chestny ZNAK","Prepare a structured CSV file for subsequent upload.","demos/txt-to-csv.html"]],cvLabel:"FULL CV",cvTitle:"One universal profile for candidate evaluation.",cvText:"The PDF is ready to share or print. DOCX is available for recruiter workflow. The document language follows the selected site language.",cvOther:"Other languages",contactLabel:"CONTACT",contactTitle:"Ready to discuss the role, working format and relocation to Serbia.",footer:"Business systems and automation portfolio",commandText:"Open candidate profile",caseStatus:"IN PRODUCTION",pdfHint:"Ready to share and print",docxHint:"Editable document",systemStatus:"SYSTEM READY"},sr:{metaTitle:"Mikhail Fedrunov — 1C programer / poslovni analitičar / stručnjak za automatizaciju",nav:{profile:"Profil",experience:"Iskustvo",cases:"Projekti",skills:"Veštine",cv:"CV"},heroKicker:"PROFIL STRUČNJAKA · POSLOVNI SISTEMI",heroTitle:"Automatizujem poslovne procese, ne samo funkcije.",heroLead:"1C programer i poslovni analitičar sa praktičnim iskustvom u automatizaciji prodaje, proizvodnje, skladišta i računovodstva. Samostalno vodim zadatak od razgovora sa korisnicima i analize procesa do projektovanja, razvoja, testiranja, puštanja u rad i podrške. Podržavam više od 300 korisnika i devet informacionih baza, uključujući tri produkcione baze proizvodne i distributivne kompanije. Najjače oblasti su DCS i složeni upiti, ekstenzije i spoljne obrade, HTTP/True API, JSON/XML/FTP, pozadinski poslovi, označavanje robe i DataMatrix, razmene između baza i štampani obrasci.",role:"1C programer / poslovni analitičar / stručnjak za automatizaciju",location:"Simferopolj, Krim",relocation:"Spreman za preseljenje u Srbiju odmah nakon ponude; potrebna je podrška poslodavca za radnu dozvolu i legalizaciju boravka.",status:"Otvoren za ponude u Srbiji",buttons:{pdf:"Otvori PDF",docx:"Preuzmi DOCX",contact:"Kontakt"},formLabels:{status:"Status",focus:"Specijalizacija",scale:"Obim",location:"Lokacija"},formValues:{status:"Spreman za preseljenje",focus:"1C · analiza · integracije",scale:"300+ korisnika · 9 baza",location:"Simferopolj → Srbija"},metrics:[["300+","korisnika u podršci"],["3 / 9","produkcionih / ukupno baza"],["end to end","od zahteva do produkcije"],["nekoliko dana","ručnog rada štedi ključni alat za proveru"]],profileLabel:"VREDNOST ZA KOMPANIJU",profileTitle:"Razvoj, analiza i pouzdanost u jednom stručnjaku.",profileText:"Objedinjuje tri discipline u jednoj odgovornoj ulozi: 1C razvoj, poslovnu analizu i kontrolu kvaliteta podataka i integracija.",competencies:[["1C razvoj","1C:Enterprise 8.3; upravljanje trgovinom, računovodstvo i zarade; ekstenzije; spoljne obrade i izveštaji; dokumenti; registri podataka; forme i štampani obrasci."],["Upiti i analitika","Data Composition System, složeni upiti, spajanja, grupisanja, analitičke dimenzije, poređenje podataka između izvora i izveštaji za menadžment."],["Integracije","HTTP i True API, autorizacija tokenima, Standard Subsystems Library, FTP, JSON, XML, CSV i TXT."],["Automatizacija i pouzdanost","Pozadinski i planirani poslovi, paketna obrada, kontrola duplikata, evidencija grešaka, provera API-ja i međusistemskih razmena."],["Poslovna analiza","Razgovori sa korisnicima, analiza postojećeg procesa, projektovanje ciljnog rešenja, usaglašavanje logike, puštanje u rad i obuka korisnika."],["Aplikativna podrška","Podrška za više od 300 korisnika i tri produkcione plus šest testnih/razvojnih baza."]],experienceLabel:"ISKUSTVO",experienceTitle:"Razumem operacije iznutra i pretvaram zahteve u radne alate.",experience:[{company:"TD Vremya, Simferopolj",role:"Sistemski programer / 1C programer",period:"Januar 2026 — danas",intro:"Proizvodna i distributivna kompanija. Glavni stručnjak za aplikativne zadatke u 1C: razvoj, integracije, analitika i podrška korisnicima.",bullets:["Podržavam više od 300 korisnika, tri produkcione baze i šest testnih ili razvojnih baza.","Prikupljam zahteve računovodstva, prodaje, logistike, skladišta, proizvodnje i menadžmenta; predlažem tehničko rešenje i dovodim ga do rada u produkciji.","Razvijam ekstenzije, spoljne obrade i izveštaje, dokumente, registre podataka, forme, DCS izveštaje i štampane obrasce.","Kreiram integracije preko HTTP/True API-ja, FTP-a, JSON-a i XML-a; koristim Standard Subsystems Library za serverske zahteve, autorizaciju i tokene.","Podešavam pozadinske i planirane poslove za preuzimanje datoteka, masovnu proveru, obradu kodova i slanje izveštaja.","Održavam razmene između baza, planove razmene, XML prenose i pravila Data Conversion 2.1.","Testiram izmene na testnim bazama, podržavam puštanje u rad i ispravljam greške koje pronađu korisnici.","Pišem korisnička uputstva i objašnjavam poslovnu logiku novih alata i izmenjenih procesa."]},{company:"OVK-Term, Simferopolj",role:"1C operater → logističar → menadžer akata → zamenik rukovodioca skladišta",period:"Januar 2023 — novembar 2025",intro:"Napredovao sam od operativnog rada u 1C do koordinacije skladišnih i logističkih procesa. Ovo iskustvo je formiralo snažnu poslovnu osnovu za kasniju automatizaciju.",bullets:["Radio sam sa punim ciklusom kretanja robe: prijem, skladištenje, premeštanje, komisioniranje, otprema, dostava, povrati i inventure.","Analizirao sam razlike između podataka u 1C, primarne dokumentacije i stvarnih skladišnih i logističkih operacija.","Koordinirao sam skladište, logističare, vozače, menadžere i računovodstvo i usaglašavao zahteve više odeljenja.","Kontrolisao sam ispravnost akata, premeštanja, otpreme, zaliha i prateće dokumentacije.","Kreirao sam Excel alate sa složenim formulama, pivot tabelama i VBA-om radi smanjenja ručne pripreme i provere podataka.","Formalizovao sam radne procese i pripremao uputstva za zaposlene."]}],casesLabel:"PROJEKTI U PRODUKCIJI",casesTitle:"Projekti sa poslovnim kontekstom, realizacijom i rezultatom.",casesIntro:"Prelazak mišem prikazuje strukturu; klik otvara ceo projekat.",cases:[{id:"CASE-001",title:"Provera izlaznih UTD dokumenata u sistemu Chestny ZNAK",short:"Pozadinska provera dokumenata i vlasništva nad kodovima preko True API-ja.",challenge:"EDI status u računovodstvenom sistemu nije uvek bio dovoljan. Zaposleni su dodatno ručno proveravali dokumente i kodove, što je moglo da traje nekoliko radnih dana.",solution:"Razvio sam obradu za Accounting 3.0 sa izborom organizacije i perioda. Pronalazi prodaju i UTD dokumente za proveru, poziva True API po identifikatoru dokumenta, izdvaja kodove iz UTD-a i proverava trenutnog vlasnika svakog koda. Masovna provera radi kroz pozadinske zadatke, uz praćenje statusa i jasan završni protokol.",result:"Korisnik dobija jednu tabelu sa prodajnim dokumentima, UTD-ovima, statusima, identifikatorima i brojem kodova, kao i opcioni TXT izvoz. Višednevna ručna provera zamenjena je jednim pokretanjem i pregledom rezultata.",stack:"1C Accounting 3.0 · True API · HTTP · SSL · Standard Subsystems Library · pozadinski poslovi · DataMatrix"},{id:"CASE-002",title:"Uvoz DataMatrix kodova iz mobilne aplikacije",short:"Automatsko preuzimanje JSON-a sa FTP-a i povezivanje sa podacima u 1C.",challenge:"Prodajni agenti skeniraju prodajno mesto i kodove paketa/kartona tokom gotovinske prodaje. Poslovanju je bio potreban centralizovan način prikupljanja i povezivanja tih podataka sa evidencijom.",solution:"Implementirao sam preuzimanje JSON datoteka sa FTP-a i obradu datuma, agenta, prodajnog mesta i DataMatrix kodova. Dodao sam povezivanje sa korisnicima, partnerima, artiklima i rutama, sopstveni registar podataka, kontrolu duplikata i evidenciju grešaka.",result:"Podaci automatski ulaze u 1C i spremni su za analitiku bez ručnog spajanja datoteka. Greške povezivanja se čuvaju i evidentiraju za naknadnu obradu.",stack:"1C Trade Management · FTP · JSON · planirani poslovi · registri podataka · DataMatrix"},{id:"CASE-003",title:"Kontrola skeniranja po agentima i odeljenjima",short:"Poređenje skenova iz aplikacije sa stvarnom prodajom iz računovodstva.",challenge:"Menadžmentu je bilo potrebno da vidi koji agenti skeniraju označenu robu, gde skenovi nedostaju i da li količine odgovaraju stvarnoj prodaji.",solution:"Razvio sam izveštaje po odeljenjima i agentima, preračun blokova i kartona u pakete, zbirne rezultate i posebne liste zaposlenih bez skenova. Podaci aplikacije se porede sa prodajom iz računovodstvene baze.",result:"Menadžeri dobijaju jasnu sliku po svakom odeljenju i agentu: nema skeniranja, nepotpuno skeniranje i razlike u odnosu na računovodstvo.",stack:"1C · DCS · složeni upiti · registri podataka · poređenje između baza · Excel"},{id:"CASE-004",title:"Lokalni veb alati za kodove označavanja",short:"Skup HTML/JavaScript alata za masovnu obradu TXT, CSV i XML datoteka.",challenge:"Veliki skupovi kodova često su ručno spajani, poređeni, čišćeni i konvertovani, uz zahtev da se nijedan DataMatrix znak ne promeni.",solution:"Napravio sam samostalne alate u pregledaču za izdvajanje iz XML-a, konverziju CSV↔TXT, pronalaženje i uklanjanje duplikata, spajanje datoteka, uklanjanje otpisanih kodova, razdvajanje paketa i kartona, zbirne rezultate i obrnutu proveru.",result:"Masovne operacije rade lokalno bez instalacije softvera i bez slanja datoteka eksternim servisima. Korisnik vidi statistiku i greške i dobija rezultat za preuzimanje.",stack:"HTML · CSS · JavaScript · File API · CSV/XML/TXT · DataMatrix"},{id:"CASE-005",title:"Štampani obrasci i grupno kreiranje PDF dokumenata",short:"Višestranični dokumenti sa dinamičkim podacima, datumima i potpisnicima.",challenge:"Standardni obrasci nisu pokrivali interna pravila za pravna lica, potpisnike, datume i komplete dokumenata.",solution:"Razvijao sam transportne fakture, zahteve, obaveštenja i interne obrasce. Implementirao sam dinamičke potpisnike, zbirne vrednosti, datume radnih dana, višestranični izlaz i grupno čuvanje pojedinačnih PDF dokumenata.",result:"Dokumenti se generišu prema pravilima kompanije i spremni su za štampu bez ručnih ispravki. Grupni izvoz ubrzava pripremu kompleta.",stack:"1C · spreadsheet document · štampani obrasci · PDF"},{id:"CASE-006",title:"Podrška razmenama između baza",short:"Planovi razmene, Data Conversion 2.1, XML i selektivni prenos dokumenata.",challenge:"Razmene između baza zahtevale su izmene pravila, kontrolu registracije objekata i analizu grešaka prenosa.",solution:"Dorađivao sam planove razmene i pravila Data Conversion 2.1, analizirao sadržaj izvoza, podešavao selektivni prenos dokumenata i radio sa XML formatom.",result:"Potrebni dokumenti i atributi prenose se predvidivo, a greške se mogu lokalizovati na pravilo ili objekat.",stack:"1C · Data Conversion 2.1 · planovi razmene · XML · pozadinski poslovi"}],caseLabels:{challenge:"Poslovni zadatak",solution:"Realizacija",result:"Rezultat",stack:"Tehnologije",open:"Otvori projekat",close:"Zatvori"},workflowLabel:"NAČIN RADA",workflowTitle:"Od korisničkog problema do stabilnog rešenja u produkciji.",workflow:[["01","Razumeti","Razgovarati sa korisnicima, proveriti dokumente i podatke i pronaći pravi uzrok problema."],["02","Projektovati","Definisati 1C objekte, integracije, provere, scenarije grešaka i jasan interfejs."],["03","Razviti","Implementirati rešenje, pozadinske procese, izveštaje i kontrolne alate."],["04","Uvesti","Testirati u posebnoj bazi, pustiti u rad, obučiti korisnike i podržati rezultat."]],skillsLabel:"TEHNOLOGIJE",skillsTitle:"Radni skup tehnologija",skills:["1C:Enterprise 8.3","Trgovina / računovodstvo / zarade","DCS i 1C jezik upita","Ekstenzije i spoljne obrade","HTTP / True API / SSL","FTP / JSON / XML / CSV / TXT","Pozadinski i planirani poslovi","Data Conversion 2.1 i planovi razmene","DataMatrix / Chestny ZNAK","HTML / CSS / JavaScript","Excel / VBA","Git / Postman — osnovno iskustvo"],toolsLabel:"RADNI DEMOI",toolsTitle:"Lokalni alati koji su stvarno korišćeni za obradu kodova.",demoOpen:"Otvori alat",demos:[["Izdvajanje kodova iz XML-a","Izdvajanje DataMatrix vrednosti iz više XML datoteka u TXT.","demos/xml-to-txt.html"],["Pronalaženje i uklanjanje duplikata","Provera velikih skupova kodova sa rezultatima i izvozom.","demos/deduplicate.html"],["Uklanjanje otpisanih kodova","Poređenje više izvora sa otpisanim kodovima i kreiranje očišćenih datoteka.","demos/remove-codes.html"],["TXT u CSV za Chestny ZNAK","Priprema strukturisanog CSV-a za kasniji uvoz.","demos/txt-to-csv.html"]],cvLabel:"POTPUN CV",cvTitle:"Jedan univerzalni profil za procenu kandidata.",cvText:"PDF je spreman za slanje ili štampu. DOCX je dostupan za rad regrutera. Jezik dokumenta prati izabrani jezik sajta.",cvOther:"Drugi jezici",contactLabel:"KONTAKT",contactTitle:"Spreman da razgovaram o ulozi, načinu rada i preseljenju u Srbiju.",footer:"Portfolio poslovnih sistema i automatizacije",commandText:"Otvori profil kandidata",caseStatus:"U PRODUKCIJI",pdfHint:"Spreman za slanje i štampu",docxHint:"Dokument za uređivanje",systemStatus:"SISTEM SPREMAN"}}])},89426,a=>{"use strict";a.s(["portfolioExtras",0,{ru:{navExtra:"Ещё работы",casesNoteTitle:"Это витрина, а не полный список",casesNote:"Ниже показаны наиболее понятные работодателю примеры. Реальный объём шире: задачи от руководства и пользователей я разбирал по сути, самостоятельно формализовал и доводил до рабочего результата, даже когда запрос звучал странно, был разовым или не имел готового технического задания.",extraLabel:"ДОПОЛНИТЕЛЬНЫЕ РЕАЛИЗОВАННЫЕ ЗАДАЧИ",extraTitle:"Ещё 18 примеров прикладной автоматизации",extraIntro:"Небольшие инструменты часто дают бизнесу не меньше пользы, чем крупные проекты: убирают повторяющиеся действия, снижают риск ошибок и возвращают сотрудникам рабочее время.",resultLabel:"Эффект",stackLabel:"Технологии",pdfBadge:"ОДИН УНИВЕРСАЛЬНЫЙ ДОКУМЕНТ",pdfHint:"PDF · подробный опыт · ключевые проекты · навыки",pdfTitle:"Полное резюме для технического руководителя и HR",pdfText:"Единое расширенное резюме объединяет разработку 1С, бизнес-анализ, интеграции, поддержку корпоративных систем и опыт реальных процессов склада и логистики.",contactText:"Открыт к предложениям в Сербии: 1С-разработка, ERP/Application Support, бизнес-анализ и интеграционные задачи. Готов к офису, гибриду или удалённой работе.",secondEmail:"Дополнительная почта",extras:[{id:"CASE-007",title:"Извлечение DataMatrix из XML",text:"Локальный инструмент разбирает входящий XML, извлекает коды маркировки, очищает строки и формирует готовый TXT/CSV для дальнейшей проверки.",result:"Ручное копирование кодов из технических файлов заменено повторяемой операцией.",stack:"XML · JavaScript · TXT · CSV · DataMatrix"},{id:"CASE-008",title:"Поиск и удаление дублей",text:"Проверка объединённых списков кодов, вывод статистики повторов и формирование очищенного файла без передачи данных внешним сервисам.",result:"Снижено количество ошибок при загрузках и сверках маркированной продукции.",stack:"JavaScript · File API · Set/Map · CSV/TXT"},{id:"CASE-009",title:"Исключение списанных и возвращённых кодов",text:"Сравнение исходного набора с файлами списаний и возвратов, фиксация найденных совпадений и подготовка остатка для следующей операции.",result:"Операторы не отправляют повторно коды, которые уже выбыли из рабочего контура.",stack:"DataMatrix · CSV · TXT · контроль множеств"},{id:"CASE-010",title:"Разделение партий, пачек и блоков",text:"Инструменты делят большие наборы по правилам операции, контролируют размер частей и формируют файлы с понятными именами и итогами.",result:"Подготовка партий стала быстрее и предсказуемее, без ручной нарезки файлов.",stack:"JavaScript · File API · DataMatrix · batch processing"},{id:"CASE-011",title:"CSV для операций в «Честном знаке»",text:"Преобразование исходных таблиц в требуемую структуру: нормализация строк, разделители, заголовки, контроль пустых значений и итоговый файл.",result:"Сотрудник получает готовый файл вместо ручной пересборки таблицы перед каждой загрузкой.",stack:"CSV · TXT · JavaScript · валидация данных"},{id:"CASE-012",title:"Многостраничные печатные формы",text:"Разработка и доработка ТТН, складских и торговых форм: реквизиты, подписанты, итоги, переносы страниц и массовое формирование PDF.",result:"Документы формируются из учётных данных без повторного ручного заполнения.",stack:"1С · табличный документ · макеты · печатные формы · PDF"},{id:"CASE-013",title:"Сопровождение обменов между базами",text:"Разбор расхождений, доработка планов обмена и правил КД 2.1, контроль XML-обмена и восстановление корректного движения данных.",result:"Пользователи быстрее возвращаются к работе, а ошибки не маскируются ручными правками.",stack:"1С · КД 2.1 · планы обмена · XML"},{id:"CASE-014",title:"СКД-отчёты для руководителей",text:"Сбор данных из документов и регистров, сложные соединения, отборы, группировки и аналитические разрезы под конкретный управленческий вопрос.",result:"Руководители получают ответ в отчёте, а не собирают его вручную из нескольких выгрузок.",stack:"СКД · язык запросов 1С · регистры · Excel"},{id:"CASE-015",title:"Excel/VBA-автоматизация в логистике",text:"До перехода в разработку создавал сверки, отчёты и макросы для актов, складских остатков, инвентаризаций и движения товара.",result:"Практический опыт бизнеса стал основой для решений, которыми реально удобно пользоваться.",stack:"Excel · VBA · логистика · складской учёт"},{id:"CASE-016",title:"Поддержка и доработка после запуска",text:"Разбор обращений пользователей, уточнение сценариев, тестирование в отдельных базах, объяснение логики и улучшение решения по обратной связи.",result:"Разработка не заканчивается кодом: инструмент встраивается в ежедневный процесс.",stack:"1С Support · внедрение · инструкции · QA mindset"},{id:"CASE-017",title:"Авторизация и получение токенов API",text:"Реализовывал получение токенов, передачу заголовков и параметров, разбор ответов и повторное выполнение запросов для интеграций с внешними сервисами.",result:"Интеграция работает из 1С без ручного получения служебных данных пользователем.",stack:"1С · БСП · HTTP · JSON · token auth"},{id:"CASE-018",title:"Фоновые загрузки с FTP",text:"Настраивал регулярное получение файлов, проверку новых данных, разбор содержимого и запись результата в информационную базу без блокировки работы пользователей.",result:"Данные поступают в учётный контур автоматически и доступны к началу рабочего анализа.",stack:"1С · FTP · фоновые задания · JSON · журналирование"},{id:"CASE-019",title:"Автоматическая рассылка отчётов",text:"Формировал отчёт по расписанию, подготавливал представление результата и отправлял его ответственным сотрудникам без ручного запуска.",result:"Регулярная информация приходит адресатам вовремя и в одинаковом формате.",stack:"1С · регламентные задания · СКД · email"},{id:"CASE-020",title:"Массовая обработка документов",text:"Создавал обработки для отбора документов по организации, периоду и статусу, выполнения контролируемых действий и вывода протокола по каждой строке.",result:"Повторяющаяся работа с группой документов выполняется одним управляемым запуском.",stack:"1С · управляемые формы · запросы · табличные части"},{id:"CASE-021",title:"Контроль и обновление идентификаторов",text:"Искал отсутствующие или некорректные идентификаторы в связанных данных, сопоставлял записи и подготавливал безопасное массовое обновление.",result:"Снижено число ошибок, возникающих из-за несвязанных документов и внешних сущностей.",stack:"1С · регистры сведений · запросы · интеграционные ID"},{id:"CASE-022",title:"Подготовка возвратов и списаний",text:"Собирал и сверял списки кодов для операций возврата и списания, разделял входные данные по назначению и формировал проверяемый результат.",result:"Сложная файловая операция стала понятной последовательностью с контролем итогового количества.",stack:"DataMatrix · CSV · TXT · сверка наборов · валидация"},{id:"CASE-023",title:"Объединение файлов и контроль итогов",text:"Инструменты принимают несколько входных файлов, нормализуют строки, объединяют данные, считают результат и отдельно показывают спорные записи.",result:"Сотрудники работают с одним проверенным результатом вместо ручной склейки файлов.",stack:"JavaScript · File API · CSV/TXT · контроль качества"},{id:"CASE-024",title:"Инструкции и передача решения пользователям",text:"Описывал назначение, последовательность действий, ограничения и разбор типовых ошибок, затем объяснял решение сотрудникам на реальных сценариях.",result:"Новый инструмент быстрее принимается командой и требует меньше повторных обращений.",stack:"документация · обучение · внедрение · пользовательская поддержка"}]},en:{navExtra:"More work",casesNoteTitle:"A showcase, not the complete list",casesNote:"The cases below are the clearest examples for an employer. The actual scope is broader: I investigated requests from managers and users, clarified the real process, translated poorly defined or unusual requests into workable requirements, and delivered the result to production.",extraLabel:"ADDITIONAL DELIVERED WORK",extraTitle:"18 more examples of practical automation",extraIntro:"Small internal tools can create as much value as large projects: they remove repetitive work, reduce errors and return productive time to employees.",resultLabel:"Impact",stackLabel:"Technology",pdfBadge:"ONE UNIVERSAL DOCUMENT",pdfHint:"PDF · detailed experience · key projects · skills",pdfTitle:"Complete CV for engineering managers and HR",pdfText:"One detailed CV combines 1C development, business analysis, integrations, corporate application support and hands-on knowledge of warehouse and logistics processes.",contactText:"Open to opportunities in Serbia: 1C development, ERP/Application Support, business analysis and integration work. Available for office, hybrid or remote work.",secondEmail:"Additional email",extras:[{id:"CASE-007",title:"DataMatrix extraction from XML",text:"A local tool parses incoming XML, extracts marking codes, normalizes rows and creates a clean TXT/CSV file for further verification.",result:"Manual copying from technical files was replaced with a repeatable operation.",stack:"XML · JavaScript · TXT · CSV · DataMatrix"},{id:"CASE-008",title:"Duplicate detection and cleanup",text:"Checks merged code lists, reports duplicate statistics and creates a clean output without sending business data to external services.",result:"Reduced errors in marking uploads and reconciliation workflows.",stack:"JavaScript · File API · Set/Map · CSV/TXT"},{id:"CASE-009",title:"Excluding written-off and returned codes",text:"Compares source data with write-off and return files, records matches and prepares the valid remainder for the next operation.",result:"Operators avoid resubmitting codes that have already left the working flow.",stack:"DataMatrix · CSV · TXT · set comparison"},{id:"CASE-010",title:"Splitting batches, packs and blocks",text:"Tools split large datasets by operational rules, validate part sizes and generate clearly named files with summary totals.",result:"Batch preparation became faster and predictable, without manual file cutting.",stack:"JavaScript · File API · DataMatrix · batch processing"},{id:"CASE-011",title:"CSV preparation for Chestny ZNAK",text:"Transforms source tables into the required structure: row normalization, delimiters, headers, empty-value checks and final export.",result:"Employees receive a ready-to-upload file instead of rebuilding a spreadsheet each time.",stack:"CSV · TXT · JavaScript · data validation"},{id:"CASE-012",title:"Complex multi-page print forms",text:"Built and refined waybills, warehouse and sales forms with requisites, signatories, totals, page breaks and bulk PDF generation.",result:"Documents are produced directly from accounting data without repeated manual entry.",stack:"1C · tabular documents · layouts · print forms · PDF"},{id:"CASE-013",title:"Data exchange support between databases",text:"Investigated discrepancies, refined exchange plans and Conversion 2.1 rules, checked XML flows and restored consistent data movement.",result:"Users return to work faster and issues are resolved at the source.",stack:"1C · Conversion 2.1 · exchange plans · XML"},{id:"CASE-014",title:"DCS reports for management",text:"Combines documents and registers through joins, filters, grouping and analytical dimensions tailored to a concrete management question.",result:"Managers receive an answer in one report instead of assembling several exports.",stack:"DCS · 1C query language · registers · Excel"},{id:"CASE-015",title:"Excel/VBA automation in logistics",text:"Before moving into development, created reconciliations, reports and macros for acts, stock, inventories and goods movement.",result:"Hands-on business experience became the foundation for tools people can actually use.",stack:"Excel · VBA · logistics · warehouse operations"},{id:"CASE-016",title:"Support and iteration after release",text:"Handles user feedback, clarifies edge cases, tests in separate databases, explains system logic and improves solutions after launch.",result:"Delivery does not stop at code: the tool becomes part of daily work.",stack:"1C Support · implementation · documentation · QA mindset"},{id:"CASE-017",title:"API authorization and token handling",text:"Implemented token retrieval, request headers and parameters, response parsing and controlled retries for integrations with external services.",result:"The integration works from 1C without users manually obtaining service credentials.",stack:"1C · BSP · HTTP · JSON · token auth"},{id:"CASE-018",title:"Background imports from FTP",text:"Scheduled file retrieval, new-data checks, content parsing and database writes without blocking everyday user work.",result:"Operational data arrives automatically and is ready for analysis at the start of the work cycle.",stack:"1C · FTP · background jobs · JSON · logging"},{id:"CASE-019",title:"Scheduled report delivery",text:"Generated reports on a schedule, prepared a consistent presentation and delivered results to responsible employees without manual launch.",result:"Recurring information reaches the right people on time and in a stable format.",stack:"1C · scheduled jobs · DCS · email"},{id:"CASE-020",title:"Bulk document processing",text:"Built processors that select documents by company, period and status, perform controlled actions and show a protocol for every record.",result:"Repetitive work across many documents is completed through one manageable run.",stack:"1C · managed forms · queries · tabular sections"},{id:"CASE-021",title:"Identifier control and updates",text:"Located missing or incorrect identifiers in connected data, matched records and prepared a controlled bulk update.",result:"Reduced failures caused by documents and external entities that were not linked correctly.",stack:"1C · information registers · queries · integration IDs"},{id:"CASE-022",title:"Return and write-off preparation",text:"Collected and reconciled marking-code lists for returns and write-offs, separated source data by operation and produced a verifiable output.",result:"A complex file workflow became a clear sequence with totals at every stage.",stack:"DataMatrix · CSV · TXT · set comparison · validation"},{id:"CASE-023",title:"File merging and total control",text:"Tools accept multiple files, normalize rows, merge datasets, calculate totals and isolate questionable records for review.",result:"Employees work with one verified result instead of manually joining files.",stack:"JavaScript · File API · CSV/TXT · data quality"},{id:"CASE-024",title:"User instructions and solution handover",text:"Documented purpose, action sequence, limitations and common errors, then explained the solution using real work scenarios.",result:"New tools are adopted faster and require fewer repeated support requests.",stack:"documentation · training · implementation · user support"}]},sr:{navExtra:"Još radova",casesNoteTitle:"Ovo je izbor primera, ne potpuna lista",casesNote:"U nastavku su primeri koji poslodavcu najjasnije pokazuju način rada. Stvarni obim je širi: zahteve rukovodilaca i korisnika analizirao sam po suštini, pretvarao nejasne ili neobične ideje u radne zahteve i dovodio rešenje do produkcije.",extraLabel:"DODATNO REALIZOVANI ZADACI",extraTitle:"Još 18 primera praktične automatizacije",extraIntro:"Mali interni alati često daju jednaku vrednost kao veliki projekti: uklanjaju ponavljajući rad, smanjuju greške i vraćaju zaposlenima radno vreme.",resultLabel:"Efekat",stackLabel:"Tehnologije",pdfBadge:"JEDAN UNIVERZALNI DOKUMENT",pdfHint:"PDF · detaljno iskustvo · ključni projekti · veštine",pdfTitle:"Kompletan CV za tehničke rukovodioce i HR",pdfText:"Jedan detaljan CV objedinjuje 1C razvoj, poslovnu analizu, integracije, podršku poslovnim aplikacijama i praktično razumevanje skladišnih i logističkih procesa.",contactText:"Otvoren sam za prilike u Srbiji: 1C razvoj, ERP/Application Support, poslovna analiza i integracije. Dostupan sam za rad iz kancelarije, hibridno ili na daljinu.",secondEmail:"Dodatni imejl",extras:[{id:"CASE-007",title:"Izdvajanje DataMatrix kodova iz XML-a",text:"Lokalni alat parsira ulazni XML, izdvaja kodove, normalizuje redove i formira čist TXT/CSV za dalju proveru.",result:"Ručno kopiranje kodova zamenjeno je ponovljivom operacijom.",stack:"XML · JavaScript · TXT · CSV · DataMatrix"},{id:"CASE-008",title:"Pronalaženje i uklanjanje duplikata",text:"Proverava objedinjene liste, prikazuje statistiku ponavljanja i formira očišćen fajl bez slanja podataka eksternim servisima.",result:"Smanjene su greške pri učitavanju i usklađivanju označene robe.",stack:"JavaScript · File API · Set/Map · CSV/TXT"},{id:"CASE-009",title:"Isključivanje otpisanih i vraćenih kodova",text:"Poredi početni skup sa fajlovima otpisa i povrata, beleži podudaranja i priprema važeći ostatak za sledeću operaciju.",result:"Operateri ne šalju ponovo kodove koji su već izašli iz radnog toka.",stack:"DataMatrix · CSV · TXT · poređenje skupova"},{id:"CASE-010",title:"Deljenje partija, paketa i blokova",text:"Alati dele velike skupove prema pravilima operacije, proveravaju veličinu delova i formiraju jasno imenovane fajlove sa zbirnim podacima.",result:"Priprema partija je brža i predvidljivija, bez ručnog sečenja fajlova.",stack:"JavaScript · File API · DataMatrix · batch processing"},{id:"CASE-011",title:"Priprema CSV-a za Chestny ZNAK",text:"Pretvara izvorne tabele u potrebnu strukturu: normalizacija redova, separatori, zaglavlja, kontrola praznih vrednosti i završni izvoz.",result:"Zaposleni dobija fajl spreman za učitavanje umesto ručne izrade tabele.",stack:"CSV · TXT · JavaScript · validacija podataka"},{id:"CASE-012",title:"Složene višestranične štampane forme",text:"Razvoj i dorada tovarnih listova, skladišnih i prodajnih obrazaca sa podacima, potpisnicima, sumama, prelomima i masovnim PDF izvozom.",result:"Dokumenti se formiraju iz knjigovodstvenih podataka bez ponovnog ručnog unosa.",stack:"1C · tabelarni dokument · makete · štampa · PDF"},{id:"CASE-013",title:"Podrška razmeni između baza",text:"Analiza razlika, dorada planova razmene i pravila Konverzije 2.1, kontrola XML toka i vraćanje doslednog kretanja podataka.",result:"Korisnici se brže vraćaju radu, a problem se rešava u izvoru.",stack:"1C · Konverzija 2.1 · planovi razmene · XML"},{id:"CASE-014",title:"DCS izveštaji za rukovodioce",text:"Spajanje dokumenata i registara, filteri, grupisanje i analitičke dimenzije prilagođene konkretnom poslovnom pitanju.",result:"Rukovodioci dobijaju odgovor u jednom izveštaju umesto sklapanja više izvoza.",stack:"DCS · 1C upiti · registri · Excel"},{id:"CASE-015",title:"Excel/VBA automatizacija u logistici",text:"Pre prelaska u razvoj pravio sam usklađivanja, izveštaje i makroe za akte, zalihe, inventure i kretanje robe.",result:"Praktično poslovno iskustvo postalo je osnova za alate koje ljudi zaista mogu da koriste.",stack:"Excel · VBA · logistika · skladište"},{id:"CASE-016",title:"Podrška i dorada nakon puštanja",text:"Obrada povratnih informacija korisnika, pojašnjenje scenarija, testiranje u odvojenim bazama, objašnjenje logike i dalja dorada.",result:"Isporuka se ne završava kodom: alat postaje deo svakodnevnog rada.",stack:"1C Support · implementacija · uputstva · QA mindset"},{id:"CASE-017",title:"API autorizacija i upravljanje tokenima",text:"Implementirao sam dobijanje tokena, zaglavlja i parametre zahteva, obradu odgovora i kontrolisano ponavljanje poziva ka eksternim servisima.",result:"Integracija radi iz 1C bez ručnog dobijanja servisnih podataka.",stack:"1C · BSP · HTTP · JSON · token auth"},{id:"CASE-018",title:"Pozadinsko učitavanje sa FTP-a",text:"Podešavao sam periodično preuzimanje fajlova, proveru novih podataka, parsiranje sadržaja i upis u bazu bez blokiranja korisnika.",result:"Podaci automatski ulaze u sistem i spremni su za analizu na početku radnog ciklusa.",stack:"1C · FTP · pozadinski zadaci · JSON · logovanje"},{id:"CASE-019",title:"Automatska distribucija izveštaja",text:"Formirao sam izveštaje po rasporedu, pripremao stabilan prikaz i slao rezultate odgovornim zaposlenima bez ručnog pokretanja.",result:"Redovne informacije stižu pravim ljudima na vreme i u istom formatu.",stack:"1C · zakazani zadaci · DCS · email"},{id:"CASE-020",title:"Masovna obrada dokumenata",text:"Razvijao sam obrade koje biraju dokumente po kompaniji, periodu i statusu, izvršavaju kontrolisane radnje i prikazuju protokol za svaki zapis.",result:"Ponavljajući rad nad grupom dokumenata završava se jednim upravljanim pokretanjem.",stack:"1C · upravljane forme · upiti · tabelarni delovi"},{id:"CASE-021",title:"Kontrola i ažuriranje identifikatora",text:"Pronalazio sam nedostajuće ili netačne identifikatore, povezivao zapise i pripremao kontrolisano masovno ažuriranje.",result:"Smanjen je broj grešaka zbog nepovezanih dokumenata i eksternih entiteta.",stack:"1C · registri informacija · upiti · integracioni ID"},{id:"CASE-022",title:"Priprema povrata i otpisa",text:"Prikupljao sam i usklađivao liste kodova za povrat i otpis, razdvajao ulazne podatke po nameni i formirao proverljiv rezultat.",result:"Složen rad sa fajlovima postao je jasna sekvenca sa kontrolom ukupnog broja.",stack:"DataMatrix · CSV · TXT · poređenje skupova · validacija"},{id:"CASE-023",title:"Spajanje fajlova i kontrola zbira",text:"Alati prihvataju više fajlova, normalizuju redove, spajaju podatke, računaju rezultat i izdvajaju sporne zapise.",result:"Zaposleni rade sa jednim proverenim rezultatom umesto ručnog spajanja.",stack:"JavaScript · File API · CSV/TXT · kvalitet podataka"},{id:"CASE-024",title:"Uputstva i predaja rešenja korisnicima",text:"Opisivao sam svrhu, korake, ograničenja i tipične greške, a zatim objašnjavao rešenje na stvarnim radnim scenarijima.",result:"Novi alat se brže usvaja i zahteva manje ponovljenih zahteva za podršku.",stack:"dokumentacija · obuka · implementacija · korisnička podrška"}]}}])}]);